// mongodb \u4E2D\u5927\u591A\u6570\u7684\u6570\u636E\u7C7B\u578B\u90FD\u53EF\u4EE5\u7528 js \u7684\u539F\u751F\u7C7B\u578B\u6765\u8868\u793A\u3002\u81F3\u4E8E\u8BF4 String \u7684\u957F\u5EA6\u662F\u591A\u5C11\uFF0CNumber \u7684\u7CBE\u5EA6\u662F\u591A\u5C11\u3002String \u7684\u6700\u5927\u9650\u5EA6\u662F 16MB\uFF0CNumber \u7684\u6574\u578B\u662F 64-bit\uFF0C\u6D6E\u70B9\u6570\u7684\u8BDD\uFF0Cjs \u4E2D \`0.1 + 0.2\` \u7684\u7ED3\u679C\u90FD\u662F\u4E71\u6765\u7684\u3002\u3002\u5C31\u4E0D\u6307\u671B\u4EC0\u4E48\u4E86\u3002\u3002
