let outputPromise = getInputPromise().then(null,function(rejected){ return 'rejected';
}); outputPromise.then(function(fulfilled){ console.log('fulfilled: ' + fulfilled);
},function(rejected){ console.log('rejected: ' + rejected);
}); /** * \u5C06inputPromise\u7684\u72B6\u6001\u7531\u672A\u5B8C\u6210\u53D8\u6210rejected */
